// ===== CONFIGURATION =====
const DEBUG_MODE = global.get("DEBUG_MODE") || false;  // Activer/désactiver les logs
const sousFlowExclus = "SousFlow_UI_Change";         // Nom du sous-flow à ne pas désactiver

// ===== RÉCUPÉRATION ÉTAT COURANT =====
const pageCourante = global.get('pageCourante') || "Accueil";
const flowCourant = global.get('flowCourant') || "Principal";
const sousFlowCourant = global.get('sousFlowCourant') || "A_Definir";

// ===== INITIALISATION MESSAGES =====
msg.dashboard = [];
let redirectNeeded = false;

// ===== JOURNALISATION (SI DEBUG) =====
if (DEBUG_MODE) {
    node.warn(`État actuel -> Page: ${pageCourante}, Flow: ${flowCourant}, Sous-Flow: ${sousFlowCourant}`);
    node.warn(`Nouvelle cible -> Page: ${msg.payload.nouvellePage}, Flow: ${msg.payload.nouveauFlow}`);
}

// ===== VÉRIFICATION CHANGEMENTS =====
// 1. Page
if (msg.payload.nouvellePage && msg.payload.nouvellePage !== pageCourante) {
    msg.dashboard.push({ show: false, page: pageCourante });
    global.set('pageCourante', msg.payload.nouvellePage);
    redirectNeeded = true;
}

// 2. Flow principal
if (msg.payload.nouveauFlow && msg.payload.nouveauFlow !== flowCourant) {
    flow.set(`${flowCourant}Actif`, false);
    flow.set(`${msg.payload.nouveauFlow}Actif`, true);
    global.set('flowCourant', msg.payload.nouveauFlow);
}

// 3. Sous-flow (avec exclusion)
if (msg.payload.nouveauSousFlow && msg.payload.nouveauSousFlow !== sousFlowCourant) {
    if (sousFlowCourant !== "A_Definir" && sousFlowCourant !== sousFlowExclus) {
        flow.set(`${sousFlowCourant}Actif`, false);
    }
    flow.set(`${msg.payload.nouveauSousFlow}Actif`, true);
    global.set('sousFlowCourant', msg.payload.nouveauSousFlow);
}

// ===== AFFICHAGE NOUVELLE PAGE =====
msg.dashboard.push({ show: true, page: msg.payload.nouvellePage });

// ===== REDIRECTION NAVIGATEUR (SI NÉCESSAIRE) =====
if (redirectNeeded && msg.payload.redirect) {
    msg.http = {
        statusCode: 302,
        headers: { "Location": `/dashboard/${msg.payload.nouvellePage}` },
        payload: ""
    };
    if (DEBUG_MODE) node.warn("Redirection vers: " + msg.http.headers.Location);
}

// ===== RETOUR DES MESSAGES =====
if (msg.http) {
    return [msg.dashboard, msg.http];  // Double sortie
} else {
    return msg.dashboard;              // Sortie simple
}

//Ici configuration des valeurs par defaut de l'IP suivant le contexte
// Le sous-menu à permis de choisir le mode de fonctionnement
//var ipcourante= global.set("Ip_Courante"); // ?
// Exécuter uniquement si le bouton a envoyé "reset" ou si IP_Courante existe
//if (msg.payload !== "reset" || msg.payload!=="$ConnectIP#" ) return null;

//Constructeur avec jsDoc pour documentation si VS Code autocomplétion
/**
 * Constructeur d'une entrée IP.
 * @param {string} id - Identifiant unique.
 * @param {string} ip - Adresse IPv4.
 * @param {string} description - Description.
 * @param {"disponible"|"indisponible"|"connecté"|"non défini"} etat - Statut.
 */
function ConstrucIP (id, ip, description, etat) {
    this.id = id;
    this.ip = ip;
    this.description = `Adresse IP : ${ip} - Cas : ${id} - ${description} `; // ok si Template literal (ES6)
    this.etat = etat;
}
// Vérification initiale critique
if (!msg.payload || typeof msg.payload !== "object") {
    node.error("Message invalide : payload manquant ou non objet", msg);
    return null;
}
// Test de l'existence de ipListe (le futur tableau d'info. sur les IP)
let ipListe = global.get("ipListe") || []; // Initialise avec un tableau vide si non existant

// Si la variable n'existe pas OU n'est pas un tableau OU est vide
if (!Array.isArray(ipListe) || ipListe.length === 0) {

    /** 
         * Crée un tableau d'IPs pour un menu dropdown.
         * @output msg.payload {Array<{id: string, ip: string, description: string, etat: string}>}
         */
    ipListe = [
        new ConstrucIP(
            "SmartP_IP_Direct",
            "192.168.48.xx",//remplacer par la valeur correcte
            "Smartphone (partage de connexion) - Activez le partage de connexion sur le smartphone embarqué",
            "indéfini"
            ),
        new ConstrucIP(
            "RPI_IP_Wifi",
            "192.168.1.40",//cas serveur maison zz adresse reseau etho 40 wifi 37
            "Serveur RPI sur réseau local (connecté à la box maison)",
            "non défini"
            )
        ];

    // Initialiser un tableau pour stocker les adresses locales recherchées
    let localIPs = [];

    // Parcourir toutes les interfaces réseau pour avoir un tableau des adresses locales IPV4
    for (const [interfaceName, interfaceData] of Object.entries(msg.payload.networkInterfaces)) {
        // Filtrer les adresses IPv4 commençant par 192.168
        const filtered = interfaceData.filter(item => {
            return item.family === "IPv4" && item.address.startsWith("192.168");
        });
        // Ajouter les résultats au tableau final
    localIPs.push(...filtered.map(ipObj => ipObj.address)); // Récupère uniquement les adresses
    }

    // Gestion des résultats IP (pour info exple chemin : payload.networkInterfaces.wlan0[3].address)
    if (localIPs.length === 1) {
        const ipLocale = new ConstrucIP("SmartPiloteViaBox", localIPs[0], "Le smartphone pilote utilise une adresse fourni par la box","connecté" );
        ipListe.push(ipLocale);
    } 
    else if (localIPs.length < 1) {
        const ipLocale = new ConstrucIP("SmartPiloteViaBox", "", "Aucune adresse IP 192.168 trouvée", "indisponible");
        ipListe.push(ipLocale);
    } 
    else {
        //Ajouter les IPs locales avec vos règles spécifiques
        localIPs.forEach((ip, index) => {
            ipListe.push(
                new ConstrucIP(
                    `SmartPiloteViaBox-${index + 1}`, // ID auto-incrémenté
                    ip,
                    "IP local disponible", // Description commune
                    "indéfini" // État fixe
                )
            );
        });
    };

    // Cherche si la liaison par internet distant existe :
    if (msg.payload.publicIPV4) {
        ipListe.push(
            new ConstrucIP(
            "RPI_IP_Serveur",
            msg.payload.publicIPV4,
            "Serveur RPI distant exposé Internet - (Nécessite une carte SIM sur le Smartphone embarqué)",
            "disponible"
            )
        );
    }
    else{

        ipListe.push(
            new ConstrucIP(
             "RPI_IP_Serveur",
             "",
             "Serveur RPI distant exposé Internet - (Nécessite une carte SIM sur le Smartphone embarqué)",
             "indisponible"
            )
        );
    };
    //conserver la dernière liste validée
    global.set("ipListe", ipListe, "file"); // stockage persistant
    global.set("ipListe", ipListe); // actualiser globale courant
    msg.payload = ipListe;

}

return msg;

const liste = global.get("ipListe") || [];

// Vérifie qu'on a bien un tableau
if (!Array.isArray(liste)) {
    node.warn("ipListe n'est pas un tableau !");
    return null;
}

msg.ui_update = {
    options: liste.map(ip => ({
        label: `${ip.description} [${ip.etat}]`,
        value: ip.id
    }))
};

msg.payload = null;
return msg;

// Récupère l’ID sélectionné
const selectedId = flow.get("ipSelectionTemp");
const ipListe = global.get("ipListe") || [];

// Marquer tous à leur état initial sauf celui sélectionné
ipListe.forEach(ip => {
    if (ip.id === selectedId) {
        ip.etat = "ipCourante";
        global.set("Ip_Courante", ip.ip);// actualise l'IP_Courante ds global
        msg.payload = `IP actuelle : ${ip.ip}`;
        msg.topic = "Connexion"
    } else if (ip.etat === "ipCourante") {
        ip.etat = "disponible"; // ou garder l'état précédent
    }
});

// Mise à jour globale
global.set("ipListe", ipListe);
global.set("ipListe", ipListe, "file");// je l'inclus ds la mémoire stable
return msg;

//Affichage du groupe Grpe_On_Choix_IP
//Déf affichage
msg = {
    payload: {
        pages: {
            show: ["P_Accueil"],
            focus: "P_Accueil"
        },
        groups: {
            show: ["Grpe_On_Choix_IP"],
        }
    },
    topic: "ip"
};

return msg;

/***********************************************************************
 * SOUS-FLOW : SF_ReglesMinimales_V1
 * VERSION   : V1
 * RÈGLES    : R1 (Urgence), R2 (Mode ARRET), R3 (Reset système)
 *
 * RÔLE :
 * Appliquer les règles NON CONFIGURABLES garantissant la sécurité
 * et la cohérence globale du système.
 *
 * PRINCIPES :
 * - CfgS est la variable MAÎTRE
 * - Aucun effet matériel direct ici
 * - Mise à jour des variables globales uniquement
 * - Les commandes réelles seront émises par RZ_GestionFlux
 *
 * FORMAT msg ATTENDU :
 * msg.payload = {
 *   var  : "CfgS" | autre,
 *   prop : "modeRZ" | "urg" | "reset" | autre,
 *   val  : valeur
 * }
 *
 * SORTIE :
 * - return msg  -> changement accepté / propagé
 * - return null -> changement rejeté (sécurité)
 ***********************************************************************/

/* =======================
   Accès aux variables globales
   ======================= */
let cfg = global.get("CfgS") || {};
let moteurs = global.get("moteurs") || {};

/* =======================
   R1 — URGENCE ACTIVE
   ======================= */
/*
 * Objectif :
 * - Arrêt immédiat des moteurs
 * - Blocage des commandes dangereuses
 * - Autoriser UNIQUEMENT la sortie vers un état sûr
 */
if (cfg.urg === 1 || cfg.urg === true) {

    // Arrêt moteur systématique
    moteurs.act = 0;
    moteurs.spd = 0;
    moteurs.dir = 0;
    global.set("moteurs", moteurs);

    // Si tentative de changement de modeRZ
    if (msg.payload?.var === "CfgS" && msg.payload?.prop === "modeRZ") {

        // Autorisés uniquement : ARRET ou VEILLE
        if (!["ARRET", "VEILLE"].includes(msg.payload.val)) {
            node.warn("R1 : changement de modeRZ refusé (urgence active)");
            return null; // REJET
        }
    }

    // Toute autre commande moteur est ignorée
    if (msg.payload?.var === "moteurs") {
        return null;
    }

    // Passage autorisé (ex : clear/reset)
    return msg;
}

/* =======================
   R3 — RESET SYSTÈME
   ======================= */
/*
 * Objectif :
 * - Revenir à un état neutre connu
 * - Réinitialiser les variables critiques
 * - Clear automatique du reset
 */
if (cfg.reset === 1 || cfg.reset === true) {

    // Arrêt moteurs
    moteurs.act = 0;
    moteurs.spd = 0;
    moteurs.dir = 0;

    // État système sûr
    cfg.modeRZ = "VEILLE";
    cfg.reset = 0;

    // Mise à jour globals
    global.set("moteurs", moteurs);
    global.set("CfgS", cfg);

    // Marqueur système (debug / UI / logs)
    msg._systemReset = true;

    node.warn("R3 : reset système appliqué");

    return msg;
}

/* =======================
   R2 — MODE ARRET
   ======================= */
/*
 * Objectif :
 * - Interdire toute propulsion
 * - Garantir l'immobilité
 */
if (cfg.modeRZ === "ARRET") {

    moteurs.act = 0;
    moteurs.spd = 0;
    moteurs.dir = 0;
    global.set("moteurs", moteurs);

    // Refus de toute commande moteur
    if (msg.payload?.var === "moteurs") {
        node.warn("R2 : commande moteur rejetée (mode ARRET)");
        return null;
    }
}

/* =======================
   Fin — aucune règle bloquante
   ======================= */
return msg;

/* =======================
   R4 — MODE AUTONOME
   ======================= */
/*
 * Objectif :
 * - Autoriser le pilotage direct SE ↔ Arduino
 * - SP reste maître du mode
 * - Toujours permettre la sortie du mode autonome
 */
if (cfg.modeRZ === "AUTONOME") {

    // Interdiction des commandes moteurs venant de SP
    if (msg.payload?.var === "moteurs") {
        node.warn("R4 : commande moteur ignorée (mode AUTONOME)");
        return null;
    }

    // Autoriser changement de modeRZ (sortie AUTONOME)
    if (msg.payload?.var === "CfgS" && msg.payload?.prop === "modeRZ") {
        return msg;
    }

    // Interdire toute tentative de prise de contrôle moteur SP
    if (msg.payload?.source === "SP" && msg.payload?.type === "CMD_MOTEUR") {
        return null;
    }
}

/* =======================
   R5 — RESTRICTIONS AUTONOME
   ======================= */
/*
 * Objectif :
 * - Désactiver moteurs, odométrie, laisse
 * - Garder servos et capteurs actifs
 */
if (cfg.modeRZ === "AUTONOME") {

    // Blocage moteur côté SP
    moteurs.act = 0;
    moteurs.spd = 0;
    moteurs.dir = 0;

    global.set("moteurs", moteurs);

    // Flags d'état global (utilisés par UI & flux)
    global.set("flag_moteur_dispo", false);
    global.set("flag_odom_dispo", false);
    global.set("flag_laisse_active", false);

    // UI : masquer pilotage moteur
    global.set("ui_grp_pilotage_moteur", false);
}

/* =======================
   R6 — MODE FIXE
   ======================= */
/*
 * Objectif :
 * - Aucun déplacement possible
 * - Servos et capteurs autorisés
 */
if (cfg.modeRZ === "FIXE") {

    // Blocage total moteurs
    moteurs.act = 0;
    moteurs.spd = 0;
    moteurs.dir = 0;
    global.set("moteurs", moteurs);

    // Rejet de toute commande moteur
    if (msg.payload?.var === "moteurs") {
        node.warn("R6 : commande moteur rejetée (mode FIXE)");
        return null;
    }

    // UI : pas de pilotage moteur
    global.set("ui_grp_pilotage_moteur", false);
}

/* =======================
   R7 — CONTRAINTES TYPE DE PILOTAGE
   ======================= */
/*
 * Règles :
 * - LAISSE autorisée uniquement en DEPLACEMENT
 * - JOYSTICK autorisé en FIXE mais sans déplacement
 * - Les servos restent toujours autorisés
 */

// --- Cas interdit : LAISSE hors DEPLACEMENT
if (cfg.typePtge === "LAISSE" && cfg.modeRZ !== "DEPLACEMENT") {

    node.warn("R7 : combinaison interdite LAISSE / modeRZ ≠ DEPLACEMENT");

    // Annulation de la laisse
    global.set("flag_laisse_active", false);

    // Rejet du changement de type de pilotage
    if (msg.payload?.var === "CfgS" && msg.payload?.prop === "typePtge") {
        return null;
    }
}

// --- Cas JOYSTICK en mode FIXE
if (cfg.typePtge === "JOYSTICK" && cfg.modeRZ === "FIXE") {

    // Déplacement interdit
    global.set("flag_deplacement_autorise", false);

    // Servos toujours autorisés
    global.set("flag_servos_autorises", true);

    // Si commande moteur -> rejet
    if (msg.payload?.var === "moteurs") {
        node.warn("R7 : commande moteur rejetée (JOYSTICK + FIXE)");
        return null;
    }
}

/* =======================
   R8 — UI PAR DÉFAUT : JOYSTICK VIRTUEL
   ======================= */
/*
 * Règle :
 * - Si pilotage actif
 * - Et typePtge ≠ LAISSE
 * => affichage joystick virtuel par défaut sur SP
 */

if (cfg.typePtge && cfg.typePtge !== "LAISSE") {

    global.set("ui_affichage_joystick_virtuel", true);

} else {

    global.set("ui_affichage_joystick_virtuel", false);
}

/* =======================
   R9 — RESTRICTIONS MOTEUR PARTIELLES
   ======================= */
/*
 * Objectif :
 * - Désactiver uniquement les moteurs si nécessaire
 * - Conserver servos et capteurs actifs
 */

if (["AUTONOME", "FIXE"].includes(cfg.modeRZ)) {

    // Moteurs indisponibles
    global.set("flag_moteur_dispo", false);

    // Servos toujours autorisés
    global.set("flag_servos_autorises", true);

    // Capteurs autorisés
    global.set("flag_capteurs_autorises", true);

    // Masquage UI pilotage moteur
    global.set("ui_grp_pilotage_moteur", false);

} else {

    // Cas général (ex : DEPLACEMENT)
    global.set("flag_moteur_dispo", true);
}


/* =======================
   R10 — COHÉRENCE UI / ÉTAT SYSTÈME
   ======================= */
/*
 * Objectif :
 * - Garantir que l’UI reflète exactement les capacités réelles
 */

global.set("ui_autorise_pilotage_moteur", global.get("flag_moteur_dispo"));
global.set("ui_autorise_pilotage_servos", global.get("flag_servos_autorises"));
global.set("ui_autorise_capteurs", global.get("flag_capteurs_autorises"));


/* =======================
   R11 — VERROUILLAGE DES TRANSITIONS DE MODES
   ======================= */
/*
 * Objectif :
 * - Empêcher les transitions dangereuses ou incohérentes
 */

if (msg.payload?.var === "CfgS" && msg.payload?.prop === "modeRZ") {

    const ancienMode = cfg.modeRZ;
    const nouveauMode = msg.payload.val;

    // Transitions interdites
    const transitionsInterdites = [
        { from: "ARRET", to: "DEPLACEMENT" }
    ];

    const interdite = transitionsInterdites.some(t =>
        t.from === ancienMode && t.to === nouveauMode
    );

    if (interdite) {
        node.warn(`R11 : transition interdite ${ancienMode} → ${nouveauMode}`);
        return null;
    }
}

/* =======================
   R12 — PRIORITÉ ABSOLUE URGENCE
   ======================= */
/*
 * Objectif :
 * - Garantir que l’état d’urgence reste dominant
 * - Bloquer toute action non liée à la sortie de crise
 */

if (cfg.urg === 1 || cfg.urg === true) {

    // Autorisés uniquement :
    // - clear urgence
    // - reset
    // - passage ARRET / VEILLE
    const autoriseEnUrgence =
        (msg.payload?.var === "CfgS" &&
            ["urg", "reset", "modeRZ"].includes(msg.payload.prop)) ||
        msg._systemReset === true;

    if (!autoriseEnUrgence) {
        node.warn("R12 : message bloqué (urgence prioritaire)");
        return null;
    }
}


/* =======================
   R13 — GARDE-FOU FINAL
   ======================= */
/*
 * Objectif :
 * - Garantir la cohérence minimale du message sortant
 * - Marquer les messages validés
 */

// Vérification structure minimale
if (!msg.payload || !msg.payload.var || !msg.payload.prop) {
    node.warn("R13 : message rejeté (payload incomplet)");
    return null;
}

// Interdiction explicite de commandes moteur si moteurs indisponibles
if (
    msg.payload.var === "moteurs" &&
    global.get("flag_moteur_dispo") === false
) {
    node.warn("R13 : commande moteur bloquée (flag_moteur_dispo = false)");
    return null;
}

// Marquage de validation
msg._validatedBy = "SF_ReglesMinimales_V1";
msg._timestamp = Date.now();

// Passage autorisé
return msg;

// R0 – Détection d'urgence
// ------------------------
// Objectif :
// - Identifier une urgence système
// - Poser global.urgenceActive = true si nécessaire
// - Annoter msg.urgence

let urgence = false;
let cause = null;

// Cas typiques d'urgence (V1)
if (msg.eventType === "SYSTEM" && msg.payload?.type === "EMERGENCY") {
    urgence = true;
    cause = "SYSTEM_EMERGENCY";
}

if (msg.eventType === "VPIV" && msg.payload?.urgence === true) {
    urgence = true;
    cause = "ARDUINO_URGENCE";
}

if (msg.eventType === "UI" && msg.payload?.action === "EMERGENCY_STOP") {
    urgence = true;
    cause = "UI_EMERGENCY";
}

// Mise à jour état global
if (urgence) {
    global.set("urgenceActive", true);
    global.set("urgenceCause", cause);
    msg.urgence = { active: true, cause };
} else {
    msg.urgence = { active: false };
}

return msg;

// R1 – Application de l'urgence
// -------------------------------
// Si urgence active :
// - Forcer arrêt moteurs
// - Interdire transitions
// - Préparer message UI & VPIV

if (msg.urgence?.active === true) {
    // Forçage état sûr
    global.set("modeRZ", 0); // ARRET

    // Désactivation ciblée
    global.set("moteurs.act", false);
    global.set("odometrie.act", false);

    msg.payload = {
        modeRZ: 0,
        moteurs: "OFF",
        odometrie: "OFF",
        urgence: msg.urgence
    };

    msg.route = "URGENCE";
}

return msg;

// R2 – Clear urgence
// -------------------
// Autorise sortie d'urgence uniquement via action explicite

if (msg.eventType === "UI" && msg.payload?.action === "CLEAR_URGENCE") {
    global.set("urgenceActive", false);
    global.set("urgenceCause", null);

    // Retour sûr
    global.set("modeRZ", 1); // VEILLE

    msg.payload = {
        modeRZ: 1,
        info: "Urgence levée – retour en VEILLE"
    };

    msg.route = "CLEAR_URGENCE";
}

return msg;

// R0 – Chargement des règles dynamiques
// -------------------------------------
// Règles stockées côté Node-RED (admin)
// Format attendu (V1 simplifié) :
// [ { id, condition(ctx), action(ctx) } ]

let rules = global.get("rulesDynV1") || [];

msg.rulesDyn = Array.isArray(rules) ? rules : [];
return msg;

// R1 – Application des règles dynamiques (STUB)
// ----------------------------------------------
// Chaque règle :
// - teste une condition
// - applique une action non critique

let ctx = {
    modeRZ: global.get("modeRZ"),
    typePtge: global.get("typePtge"),
    urgenceActive: global.get("urgenceActive") === true
};

let applied = [];

for (let rule of msg.rulesDyn) {
    try {
        // STUB : à remplacer par vrai moteur de règles
        if (typeof rule === "object" && rule.enabled === true) {
            applied.push(rule.id || "rule_sans_id");
        }
    } catch (e) {
        node.warn("Erreur règle dynamique : " + e.message);
    }
}

if (applied.length > 0) {
    msg.infoDyn = {
        appliedRules: applied,
        ctx
    };
    msg.route = "INFO";
}

return msg;

// === SF_Stabilisation V1 ===
// Synthèse état système

// Lecture sécurisée des entrées
const modeRZ = (msg.modeRZ !== undefined)
    ? msg.modeRZ
    : global.get("modeRZ");

const urgence = (msg.urgence !== undefined)
    ? msg.urgence === true
    : global.get("urgence") === true;

const incoherence = msg.incoherenceDetected === true;

let stateLevel = "INFO";
let stateMessage = "État système nominal";

// 🔴 Priorité absolue : urgence
if (urgence) {
    stateLevel = "ERROR";
    stateMessage = "Urgence active – système bloqué";
}
// ⚠️ Incohérence fonctionnelle
else if (incoherence) {
    stateLevel = "WARN";
    stateMessage = "Configuration incohérente détectée";
}
// 🟢 Modes actifs
else if (modeRZ === 3 || modeRZ === 4) { // DEPLACEMENT / AUTONOME
    stateLevel = "OK";
    stateMessage = "Fonctionnement actif";
}
// ℹ️ Cas par défaut
else {
    stateLevel = "INFO";
    stateMessage = "Système en attente";
}

// Mémorisation centrale
global.set("stateLevel", stateLevel);

// Enrichissement message sortant
msg.stateLevel = stateLevel;
msg.stateMessage = stateMessage;
msg.modeRZ = modeRZ;
msg.urgence = urgence;

return msg;

// ==================================================
// SF_Dispatcher_EtatGlobal – V1 CORRIGÉ
// Rôle : garantir le format canonique RAW
// AUCUNE interprétation
// ==================================================

// --- Source ---
if (!msg.source) {
    msg.source = "UNKNOWN";
}

// --- Event type ---
msg.eventType = "RAW";

// --- Intent ---
if (!msg.intent) {
    msg.intent = "UNKNOWN";
}

// --- Payload ---
if (!msg.payload) {
    msg.payload = {};
}

// --- Meta ---
msg.meta = msg.meta || {};
msg.meta.topic = msg.meta.topic || msg.topic || null;
msg.meta.origin = msg.meta.origin || "RZ_GestionFlux";

// --- Timestamp ---
msg.timestamp = msg.timestamp || Date.now();

// Nettoyage minimal (on ne détruit rien d’utile)
delete msg.urgent;
delete msg.priority;

return msg;

// ================================
// SF_ValidationIntent_V1
// Validation centrale des intents
// ================================

// ---- Lecture du contexte global ----
const modeRZ = global.get("modeRZ") || "ARRET";
const modePtge = global.get("modePtge") || "JOYSTICK";
const sttActive = global.get("STT_active") === true;
const urgence = global.get("urgenceActive") === true;

// ---- Structure attendue ----
// msg.intent = {
//   source: "UI" | "STT",
//   type: "CONVERSATION" | "COMMAND",
//   action: string,
//   target: string,
//   value: any
// }

if (!msg.intent) {
    msg.validation = "REFUSED";
    msg.refusalReason = "INTENT_ABSENT";
    return msg;
}

// ---- Urgence prioritaire ----
if (urgence) {
    if (msg.intent.action === "ARRET" || msg.intent.action === "CLEAR_URGENCE") {
        msg.validation = "OK";
        msg.planActions = [msg.intent];
        return msg;
    }

    msg.validation = "REFUSED";
    msg.refusalReason = "URGENCE_ACTIVE";
    return msg;
}

// ---- STT actif : arbitrage vocal ----
if (sttActive) {

    // Mode NON vocal → conversation uniquement
    if (modePtge !== "VOCALE") {

        if (msg.intent.type === "CONVERSATION") {
            msg.validation = "OK";
            msg.planActions = [];
            return msg;
        }

        // Seule commande autorisée : demander pilotage vocal
        if (msg.intent.action === "SET_PILOTAGE_VOCALE") {
            msg.validation = "OK";
            msg.planActions = [
                {
                    action: "SET_MODE_PILOTAGE",
                    value: "VOCALE"
                }
            ];
            return msg;
        }

        msg.validation = "REFUSED";
        msg.refusalReason = "STT_CONVERSATION_ONLY";
        return msg;
    }

    // Mode vocal actif → commandes autorisées
    if (modePtge === "VOCALE") {

        // Blocage des changements de modeRZ sauf ARRET
        if (msg.intent.action === "SET_MODE_RZ" && msg.intent.value !== "ARRET") {
            msg.validation = "REFUSED";
            msg.refusalReason = "MODE_CHANGE_BLOCKED_BY_STT";
            return msg;
        }
    }
}

// ---- Contraintes modeRZ ----
if (modeRZ === "FIXE" && msg.intent.target === "MOTEUR") {
    msg.validation = "REFUSED";
    msg.refusalReason = "MOTEUR_INTERDIT_MODE_FIXE";
    return msg;
}

if (modeRZ === "ARRET") {
    msg.validation = "REFUSED";
    msg.refusalReason = "MODE_ARRET";
    return msg;
}

// ---- Acceptation par défaut ----
msg.validation = "OK";
msg.planActions = [msg.intent];
return msg;

/*****************************************************
 * SF_Init_1 — Chargement enrichedVars (VERSION FINALE - 23-03-26 - rev gemini)
 * Source : Lecture physique /data/data/com.termux/files/home/.node-red/globalSave.json
 *****************************************************/

// On récupère nodeFs au lieu de fs (évite conflit avec force sensore)
const nodeFs = global.get('nodeFs'); 
const filePath = global.get("rzPath");

if (!nodeFs.existsSync(filePath)) {
    node.error("Fichier introuvable !");
    return null;
}

// --- Fonctions utilitaires de typage (votre logique métier) ---
function defaultForType(type) {
    switch (type) {
        case "boolean": return false;
        case "int": case "number": return 0;
        case "array": return [];
        case "object": return {};
        case "date": return new Date().toISOString().slice(0, 10);
        default: return "";
    }
}

function convertFromString(value, type, defaultVal) {
    if (value === null || value === undefined) {
        return defaultVal !== undefined ? convertFromString(defaultVal, type) : defaultForType(type);
    }
    try {
        switch (type) {
            case "int": return parseInt(value, 10);
            case "number": return parseFloat(value);
            case "boolean": return (value === true || value === "true");
            case "string": return String(value);
            case "array": return Array.isArray(value) ? value : JSON.parse(value);
            case "object": return typeof value === "object" ? value : JSON.parse(value);
            case "date": return new Date(value);
            default: return value;
        }
    } catch (err) {
        node.error(`Erreur conversion (${type}): ${err.message}`);
        return defaultForType(type);
    }
}

// --- 1. Lecture physique du fichier de sauvegarde ---
let enrichedVars = {};
try {
    if (nodeFs.existsSync(filePath)) { // Utilisation de nodeFs
        const rawData = nodeFs.readFileSync(filePath, 'utf8');
        enrichedVars = JSON.parse(rawData).enrichedVars || {};
    } else {
        node.error("Fichier globalSave.json introuvable !");
        node.status({ fill: "red", shape: "ring", text: "Fichier absent" });
        return null;
    }
} catch (e) {
    node.error("Erreur lecture fichier : " + e.message);
    return null;
}

// --- 2. Initialisation des variables globales (RAM) ---
let totalVars = 0;
let totalInstances = 0;

Object.entries(enrichedVars).forEach(([key, e]) => {
    const instances = e.instances || ["*"];
    const props = e.proprietes || [];
    let variable = {};

    instances.forEach(instance => {
        variable[instance] = {};
        props.forEach(prop => {
            const name = prop.nomP;
            const type = prop.typeP;
            const rawValue = prop.valeurs?.[instance];
            const defaultVal = prop.valeurs?.["*"];
            variable[instance][name] = convertFromString(rawValue, type, defaultVal);
        });
    });

    if (e.abbrVarG) variable._abbrVarG = e.abbrVarG;
    if (e.indexInstances) variable._indexInstances = e.indexInstances;

    // Stockage en mémoire vive (default store)
    if (instances.length === 1 && instances[0] === "*") {
        global.set(key, variable["*"]);
    } else {
        global.set(key, variable);
    }
    totalVars++;
    totalInstances += instances.length;
});

// Sauvegarde de l'objet maître en RAM pour les autres flows (ex: ui_VarG)
global.set("enrichedVars", enrichedVars);

// --- 3. Sortie et Traçabilité ---
node.status({ fill: "green", shape: "dot", text: `${totalVars} vars chargées` });

msg.topic = "INIT_VARS_OK";
msg.payload = {
    varsLoaded: true,
    varCount: totalVars,
    instanceCount: totalInstances,
    source: "globalSave.json"
};

return msg;

/*****************************************************
 * SF_Init_2 — Détection & préparation contexte réseau
 *
 * Rôle :
 * - Identifier le contexte réseau de SP (Node-RED)
 * - Déterminer le type de connexion (MAISON / PARTAGE / DISTANT)
 * - Préparer les IP candidates pour SE
 * - Initialiser les variables réseau globales
 *
 * IMPORTANT :
 * - Pas de ping
 * - Pas de MQTT
 * - Pas de VPIV
 *****************************************************/
// Le module os est automatiquement disponible via la variable définie dans l'onglet Modules
// Si nommé la variable "os", elle est directement accessible
//const os = require("os");

// ---- 1. Récupération infos réseau SP ----
let interfaces = os.networkInterfaces();
let ipLocal = null;

for (let iface in interfaces) {
    interfaces[iface].forEach(addr => {
        if (addr.family === "IPv4" && !addr.internal) {
            ipLocal = addr.address;
        }
    });
}

const hostname = os.hostname();

// ---- 2. Détermination du type réseau ----
let ipType = "INCONNU";

if (ipLocal) {
    if (ipLocal.startsWith("192.168.")) {
        ipType = "MAISON";
    } else if (ipLocal.startsWith("10.") || ipLocal.startsWith("172.")) {
        ipType = "PARTAGE";
    } else {
        ipType = "DISTANT";
    }
}

// ---- 3. Préparation des IP candidates SE ----
let seCandidates = [];

// Valeurs possibles issues config admin (si existantes)
const cfgSE = global.get("CfgSE") || {};

if (cfgSE.ipFixeMaison && ipType === "MAISON") {
    seCandidates.push(cfgSE.ipFixeMaison);
}

if (cfgSE.ipDerniereConnue) {
    seCandidates.push(cfgSE.ipDerniereConnue);
}

// Fallback générique (édition manuelle UI)
seCandidates.push("MANUEL");

// ---- 4. Configuration broker MQTT ----
let broker = {
    mode: (ipType === "MAISON") ? "LOCAL" : "DISTANT",
    host: (ipType === "MAISON") ? "rpi.local" : "broker.externe",
    port: 1883
};

// ---- 5. Écriture variables globales ----
global.set("Net_SP", {
    ipLocal,
    ipType,
    hostname
});

global.set("Net_SE", {
    ipSelected: null,
    ipCandidates: seCandidates,
    status: "NON_CONNECTE"
});

global.set("Net_Broker", broker);

// ---- 6. Sortie ----
msg.topic = "INIT_NET_OK";
msg.payload = {
    ipType,
    seCandidates,
    brokerMode: broker.mode
};

return msg;

/*****************************************************
 * SF_Init_3 — Validation connexion SE & Arduino
 *
 * Rôle :
 * - Confirmer la présence de SE et Arduino
 * - Synchroniser l’état de session INIT
 * - Autoriser la suite de l’initialisation
 *
 * IMPORTANT :
 * - Aucun envoi VPIV
 * - SP reste maître de la validation
 *****************************************************/

// ---- 1. Initialisation session si absente ----
let initSession = global.get("INIT_SESSION");

if (!initSession) {
    initSession = {
        seReady: false,
        arduinoReady: false,
        validated: false,
        timestamp: null
    };
}

// ---- 2. Analyse du message entrant ----
switch (msg.topic) {

    case "VPIV/SE/STATUS":
        if (msg.payload && msg.payload.status === "OK") {
            initSession.seReady = true;
            global.set("Net_SE", {
                ...(global.get("Net_SE") || {}),
                status: "VALIDE"
            });
        }
        break;

    case "VPIV/ARD/STATUS":
        if (msg.payload && msg.payload.status === "OK") {
            initSession.arduinoReady = true;
            global.set("Net_Arduino", {
                status: "VALIDE",
                lastSeen: new Date().toISOString()
            });
        }
        break;

    case "FORCE_VALIDATE":
        initSession.seReady = true;
        initSession.arduinoReady = true;
        break;

    default:
        // Message non pertinent pour cette étape
        return null;
}

// ---- 3. Vérification globale ----
if (initSession.seReady && initSession.arduinoReady) {

    initSession.validated = true;
    initSession.timestamp = new Date().toISOString();

    global.set("INIT_SESSION", initSession);

    msg.topic = "INIT_CONN_OK";
    msg.payload = {
        se: initSession.seReady,
        arduino: initSession.arduinoReady,
        validated: true
    };

    return msg;
}

// ---- 4. Mise à jour partielle ----
global.set("INIT_SESSION", initSession);
return null;

/*****************************************************
 * SF_Init_4 — RESET & synchronisation Arduino / SE
 *
 * Rôle :
 * - Émettre les séquences VPIV RESET
 * - Synchroniser Arduino et SE
 * - Positionner le système en modeRZ = VEILLE
 *
 * IMPORTANT :
 * - SP est maître
 * - Aucune règle métier
 *****************************************************/

// ---- 1. Vérification INIT_SESSION ----
const initSession = global.get("INIT_SESSION");

if (!initSession || initSession.validated !== true) {
    node.warn("SF_Init_4 : INIT_SESSION non validée, RESET bloqué");
    return null;
}

// ---- 2. Chargement dictionnaire ----
const enrichedVars = global.get("enrichedVars");

if (!enrichedVars) {
    node.error("SF_Init_4 : enrichedVars absent");
    return null;
}

// ---- 3. Préparation messages VPIV ----
let vpivArduino = [];
let vpivSE = [];

/*
 * Règle :
 * - Toute variable ayant une signification Arduino → Arduino
 * - Toute variable logique / applicative → SE
 * À ce stade, on envoie TOUT, le filtrage fin viendra plus tard
 */

Object.keys(enrichedVars).forEach(varKey => {

    const varDef = enrichedVars[varKey];
    if (!varDef || !varDef.abbrVarG) return;

    const abbrVar = varDef.abbrVarG;
    const instances = varDef.instances || ["*"];
    const props = varDef.proprietes || [];

    instances.forEach(inst => {
        props.forEach(prop => {

            const abbrP = prop.abbrP;
            if (!abbrP || !prop.valeurs) return;

            let value = null;

            if (prop.valeurs[inst] !== undefined) {
                value = prop.valeurs[inst];
            } else if (prop.valeurs["*"] !== undefined) {
                value = prop.valeurs["*"];
            }

            if (value === null || value === undefined) return;

            const vpivMsg = {
                v: abbrVar,
                i: inst,
                p: abbrP,
                val: value
            };

            // Heuristique simple (à raffiner plus tard)
            if (["mtr", "srv", "us", "mic", "ledring", "ledrub", "CfgS"].includes(abbrVar)) {
                vpivArduino.push(vpivMsg);
            } else {
                vpivSE.push(vpivMsg);
            }
        });
    });
});

// ---- 4. Positionnement modeRZ = VEILLE ----
const VEILLE = 1;

global.set("configuration", {
    ...(global.get("configuration") || {}),
    instances: {
        "*": {
            mode_op: VEILLE
        }
    }
});

// ---- 5. Traçabilité INIT ----
global.set("INIT_SYNC", {
    done: true,
    timestamp: new Date().toISOString(),
    arduinoCount: vpivArduino.length,
    seCount: vpivSE.length
});

// ---- 6. Sorties (multi-sorties recommandées) ----
/*
 * Sortie 1 → VPIV Arduino
 * Sortie 2 → VPIV SE
 * Sortie 3 → signal INIT terminé
 */

return [
    { topic: "VPIV/ARD/RESET", payload: vpivArduino },
    { topic: "VPIV/SE/RESET", payload: vpivSE },
    {
        topic: "INIT_SYNC_DONE",
        payload: {
            arduinoInitSent: true,
            seInitSent: true,
            modeRZ: VEILLE
        }
    }
];

