        varCount: 0,
        instanceCount: 0,
        source: "file",
        erreur: "enrichedVars absent ou vide dans le contexte fichier"
    };
    return msg;
}

node.status({ fill: "green", shape: "dot", text: `${Object.keys(enrichedVars).length} vars chargées` });

// ---- 2. Supprimer l'ancienne variable enrichedVars du store par défaut ----
global.set("enrichedVars", undefined, storeDefault);

// ---- 3. Parcourir chaque variable et créer les globales typées ----
let totalVars = 0;
let totalInstances = 0;

Object.entries(enrichedVars).forEach(([key, e]) => {
    const instances = e.instances || ["*"];
    const props = e.proprietes || [];
    let variable = {};

    instances.forEach(instance => {
        variable[instance] = {};
        props.forEach(prop => {
            const name = prop.nomP;
            const type = prop.typeP;
            const rawValue = prop.valeurs?.[instance];
            const defaultVal = prop.valeurs?.["*"];
            variable[instance][name] = convertFromString(rawValue, type, defaultVal);
        });
    });

    // Ajouter les métadonnées (abréviations, etc.)
    if (e.abbrVarG) variable._abbrVarG = e.abbrVarG;
    if (e.indexInstances) variable._indexInstances = e.indexInstances;

    // Stocker dans les variables globales (store par défaut)
    if (instances.length === 1 && instances[0] === "*") {
        global.set(key, variable["*"], storeDefault);
    } else {
        global.set(key, variable, storeDefault);
    }
    totalVars++;
    totalInstances += instances.length;
});

// ---- 4. Traçabilité ----
global.set("INIT_STATUS", {
    enrichedVarsLoaded: true,
    timestamp: new Date().toISOString(),
    varCount: totalVars,
    instanceCount: totalInstances
});

// ---- 5. Sortie ----
msg.topic = "INIT_VARS_OK";
msg.payload = {
    varsLoaded: true,
    varCount: totalVars,
    instanceCount: totalInstances,
    source: "file"
};

return msg;

