/**
 * UI_EtatSysteme_Format
 * ---------------------
 * Met en forme l’état système avec icône + couleur
 * Entrées attendues :
 *   msg.payload     : texte lisible utilisateur
 *   msg.stateLevel  : "OK" | "INFO" | "WARN" | "ERROR"
 */

let icon = "ℹ️";
let color = "#607D8B"; // gris par défaut

switch (msg.stateLevel) {
    case "OK":
        icon = "🟢";
        color = "#2E7D32"; // vert
        break;

    case "INFO":
        icon = "🔵";
        color = "#1565C0"; // bleu
        break;

    case "WARN":
        icon = "🟠";
        color = "#EF6C00"; // orange
        break;

    case "ERROR":
        icon = "🔴";
        color = "#C62828"; // rouge
        break;
}

// Texte enrichi
msg.payload = `${icon} ${msg.payload}`;

// Style dynamique (dashboard accepte msg.style)
msg.style = {
    color: color,
    "font-weight": "bold"
};

return msg;

/**
 * UI_EtatSysteme_Timeout
 * ---------------------
 * Gère le retour automatique WARN → INFO
 *
 * Entrées :
 *   msg.payload     : texte
 *   msg.stateLevel  : "OK" | "INFO" | "WARN" | "ERROR"
 *
 * Comportement :
 *   - WARN → déclenche un timer
 *   - après délai → renvoie INFO
 *   - ERROR annule tout
 */

const WARN_TIMEOUT_MS = 5000; // ⏱️ 5 secondes (modifiable)

let currentTimer = context.get("warnTimer");

// --- Si ERROR : on annule tout ---
if (msg.stateLevel === "ERROR") {
    if (currentTimer) {
        clearTimeout(currentTimer);
        context.set("warnTimer", null);
    }
    return msg;
}

// --- Si WARN : on arme un timer ---
if (msg.stateLevel === "WARN") {

    // Nettoyage ancien timer
    if (currentTimer) {
        clearTimeout(currentTimer);
    }

    // Création du nouveau timer
    const timer = setTimeout(() => {
        node.send({
            payload: "Retour à un état informatif",
            stateLevel: "INFO"
        });
    }, WARN_TIMEOUT_MS);

    context.set("warnTimer", timer);

    return msg;
}

// --- Si autre état : on annule le timer ---
if (currentTimer) {
    clearTimeout(currentTimer);
    context.set("warnTimer", null);
}

return msg;

// === Mapping EtatGlobal → UI_Accueil ===
// Source unique : msg.stateLevel, msg.stateMessage

const level = msg.stateLevel || "INFO";
const message = msg.stateMessage || "État inconnu";

// Valeurs par défaut
let color = "#9e9e9e";   // gris INFO
let icon = "info";
let label = "INFO";

// Mapping strict
switch (level) {
    case "OK":
        color = "#2e7d32"; // vert
        icon = "check_circle";
        label = "OK";
        break;

    case "WARN":
        color = "#f9a825"; // orange
        icon = "warning";
        label = "ATTENTION";
        break;

    case "ERROR":
        color = "#c62828"; // rouge
        icon = "error";
        label = "ERREUR";
        break;

    case "INFO":
    default:
        color = "#0277bd"; // bleu
        icon = "info";
        label = "INFO";
        break;
}

// Message UI standardisé
msg.payload = {
    level,
    label,
    message,
    color,
    icon
};

// IMPORTANT : ne pas modifier msg.stateLevel
return msg;

/**
 * NORMALISATION TECHNIQUE ET TRACABILITÉ
 */
msg.timestamp = Date.now();
msg.priority = "NORMAL";

// Détection de la source physique
if (msg.topic) {
    if (msg.topic.includes('/se')) msg.source = "SE";
    else if (msg.topic.includes('/a')) msg.source = "A";
}
msg.source = msg.source || "UI_INTERNAL";

return msg;

/**
 * PARSER ET ROUTEUR DE NATURE (CAT)
 * Gère le flux standard et le décapsulage STT
 */

// 1. VÉRIFICATION FORMATAIRE
let raw = msg.payload.toString().trim();
if (!raw.startsWith('$') || !raw.endsWith('#')) return null;

// 2. DÉCOMPOSITION VPIV
let content = raw.substring(1, raw.length - 1);
let parts = content.split(':');

let vpiv = {
    cat: parts[0],  
    var: parts[1],  
    inst: parts[2] || '*',
    prop: parts[3],
    val: parts[4]
};

// 3. GESTION SPÉCIFIQUE STT (Désencapsulation d'Intent)
// Format attendu : $I:STT:*:intent:{VAR:INST:PROP:VAL}#
if (vpiv.var === "STT" && vpiv.prop === "intent") {
    let capsule = vpiv.val.replace(/[{}]/g, "");
    let c = capsule.split(':');

    if (c.length >= 4) {
        msg.vpiv = {
            cat: "V", // Une intention vocale est traitée comme une commande
            var: c[0],
            inst: c[1],
            prop: c[2],
            val: c[3]
        };
        msg.source = "STT_VOICE";
        msg.priority = "HIGH";
        return msg; // Envoi direct au cerveau
    }
}

// 4. NORMALISATION DES TYPES (CSV -> Array ou Number)
if (vpiv.val.includes(',')) {
    vpiv.val = vpiv.val.split(',').map(v => isNaN(v) ? v : Number(v));
} else {
    vpiv.val = isNaN(vpiv.val) ? vpiv.val : (vpiv.val === "true" ? true : (vpiv.val === "false" ? false : Number(vpiv.val)));
}
msg.vpiv = vpiv;

// 5. LOGIQUE DE ROUTAGE ET MISE À JOUR MÉMOIRE (Global)
// Fonction utilitaire de MAJ Global
function updateGlobal(v) {
    let store = global.get(v.var) || {};
    store[v.prop] = v.val;
    global.set(v.var, store);
}

switch (vpiv.cat) {
    case "F": 
        // FLUX (Odom, Laisse, Gyro...) : Mise à jour UI directe et arrêt.
        updateGlobal(vpiv);
        return null; 

    case "I":
    case "E":
        // INFO ou EVENT : Mise à jour Réalité (UI) + Information Cerveau.
        updateGlobal(vpiv);
        if (vpiv.cat === "E") msg.priority = "CRITICAL";
        return msg;

    case "V":
        // COMMANDE (UI/STT) : Transmission Cerveau uniquement (Pas de MAJ Global ici).
        return msg;

    default:
        return null;
}

/**
 * ENCODEUR VPIV ET ROUTEUR HARDWARE
 */
let v = msg.vpiv || msg.payload;
if (!v.cat || !v.var) return null;

// Construction de la valeur String (gestion des tableaux)
let valStr = Array.isArray(v.val) ? v.val.join(',') : v.val;

// Formatage VPIV
msg.payload = `$${v.cat}:${v.var}:${v.inst || '*'}:${v.prop}:${valStr}#`;

// ROUTAGE MQTT (Choix du topic)
// Variables spécifiques au Smartphone Embarqué (SE)
const SE_VARS = ['CfgS', 'STT', 'Voice', 'CamSE', 'MicroSE', 'Appli', 'Sys'];

if (SE_VARS.includes(v.var) || v.var.startsWith('CfgS')) {
    msg.topic = "rz/vpiv/in/se";
} else {
    msg.topic = "rz/vpiv/in/a"; // Par défaut vers Arduino
}

return msg;

// Récupération des données globales
let enrichedVars = global.get("enrichedVars") || {}; 
let tableauPourUI = [];

// On réinitialise la sélection à chaque rafraîchissement de liste
flow.set("varSelected", ""); 

// Parcours de toutes les variables du fichier globalSave
Object.entries(enrichedVars).forEach(([nomVarG, e]) => {
    if (!nomVarG || !e || typeof e !== "object") return;

    // On prépare un résumé des propriétés pour l'affichage tableau
    let props = e.proprietes || [];
    let proprieteResume = props.length > 0 ? props.map(p => p.nomP).join(", ") : "";

    // On pousse l'objet complet vers le tableau UI
    tableauPourUI.push({
        nomVarG: nomVarG,
        instances: (e.instances || ["*"]).join(", "),
        proprietes: proprieteResume,
        descriptionVarG: e.descriptionVarG || "", // On garde le champ description
        dateUpdateVarG: e.dateUpdateVarG || ""    // On garde la date
    });
});

msg.payload = tableauPourUI;
return msg;

// =================================================================
// 🔹 InfosSauvegardeVars
// - Enregistre les modifs de la variable globale
// - Gère le renommage de la clé dans l'objet global
// =================================================================

const nodeFs = global.get('nodeFs');
const filePath = global.get("rzPath");

let enrichedVars = global.get("enrichedVars") || {};
let varSelected = flow.get("varSelected");
let formData = msg.payload;

if (!formData || !formData.nomVarG) return null;

let newName = formData.nomVarG.trim();
let oldName = (varSelected === "new") ? null : varSelected;

if (!oldName || !enrichedVars[oldName]) {
    // CRÉATION : Nouvel objet
    enrichedVars[newName] = {
        nomVarG: newName,
        nomCpletVarG: formData.nomCpletVarG || "",
        instances: formData.instances ? formData.instances.split(",").map(e => e.trim()) : ["*"],
        descriptionVarG: formData.descriptionVarG || "",
        dateUpdateVarG: new Date().toISOString(),
        proprietes: []
    };
} else {
    // MODIFICATION : On récupère l'existant pour ne rien écraser (les P notamment)
    let data = enrichedVars[oldName];

    if (oldName !== newName) {
        enrichedVars[newName] = data; // On déplace les données
        delete enrichedVars[oldName]; // On supprime l'ancienne clé
    }

    // Mise à jour des champs modifiables
    enrichedVars[newName].nomVarG = newName;
    enrichedVars[newName].nomCpletVarG = formData.nomCpletVarG;
    enrichedVars[newName].instances = formData.instances.split(",").map(e => e.trim());
    enrichedVars[newName].descriptionVarG = formData.descriptionVarG;
    enrichedVars[newName].dateUpdateVarG = new Date().toISOString();
}

// Persistence
global.set("enrichedVars", enrichedVars);
try {
    const toSave = { enrichedVars: enrichedVars, lastUpdate: new Date().toISOString() };
    nodeFs.writeFileSync(filePath, JSON.stringify(toSave, null, 4), 'utf8');
} catch (err) { node.error(err); }

flow.set("varSelected", newName);
msg.payload = newName;
return msg;

// 🔹 recupVarSelected
// - Détermine si on sélectionne une variable existante ou si on crée une nouvelle
// - Met à jour flow.varSelected
// - Fournit msg.info et msg.payload adaptés

let enrichedVars = global.get("enrichedVars") || {};
let listeVars = Object.keys(enrichedVars);
let varSelected = null;

// 1) Cas bouton "Ajouter une VarG"
if (msg.topic === "newVarG") {
    varSelected = "new";
}
// 2) Cas sélection dans la table
else {
    varSelected = msg.payload?.row?.nomVarG || msg.payload?.nomVarG || null;
}

// 3) Vérification : aucune sélection
if (!varSelected) {
    msg.info = (listeVars.length === 0)
        ? "⚠️ Aucune variable existante dans enrichedVars."
        : "⚠️ Aucune variable sélectionnée pour édition.";
    return msg;  // on sort proprement
}

// 4) Stockage de la sélection
flow.set("varSelected", varSelected);

// 5) Message d'info
msg.info = (varSelected === "new")
    ? "➕ Création d'une nouvelle variable."
    : `✅ Vous êtes sur la variable : ${varSelected}`;

// 6) Retour
msg.payload = varSelected;
return msg;

// =================================================================
// 🔹 prepareFormVarSelected
// - Prépare le formulaire Form_Var_Modif selon varSelected
// - Gère : création nouvelle variable, édition variable existante
// =================================================================

let enrichedVars = global.get("enrichedVars") || {};
let varSelected = flow.get("varSelected") || null;

// 1) Cas création d'une nouvelle variable
if (varSelected === "new") {
    msg.payload = {
        nomVarG: "",
        nomCpletVarG: "", // Gardé pour compatibilité
        instances: "*", 
        descriptionVarG: "- Objectif(s): \n- Origine: \n- Autres : ",
        dateUpdateVarG: new Date().toISOString()
    };
    msg.topic = "newVarG";
    return msg;
}

// 2) Cas édition d'une variable existante
if (varSelected && enrichedVars[varSelected]) {
    const selected = enrichedVars[varSelected];
    msg.payload = {
        nomVarG: selected.nomVarG || varSelected,
        nomCpletVarG: selected.nomCpletVarG || "", // On ne supprime rien
        instances: selected.instances ? selected.instances.join(", ") : "*",
        descriptionVarG: selected.descriptionVarG || "",
        dateUpdateVarG: selected.dateUpdateVarG || new Date().toISOString()
    };
    return msg;
}

// 3) Cas par défaut / Sécurité
msg.payload = {
    nomVarG: "",
    nomCpletVarG: "",
    instances: "",
    descriptionVarG: "",
    dateUpdateVarG: new Date().toISOString()
};
return msg;

const nodeFs = global.get('nodeFs');
const filePath = global.get("rzFilePath");

if (msg.payload === "confirm_clicked") {
    const varToDelete = flow.get("pendingDeletion");
    let enrichedVars = global.get("enrichedVars") || {};

    if (varToDelete && enrichedVars[varToDelete]) {
        // 1. Suppression RAM
        delete enrichedVars[varToDelete];
        global.set("enrichedVars", enrichedVars);

        // 2. Persistance Disque immédiate
        try {
            if (Object.keys(enrichedVars).length === 0) {
                // Optionnel : protéger si on veut interdire de supprimer la DERNIÈRE variable
                // ou simplement autoriser un fichier vide :
                nodeFs.writeFileSync(filePath, JSON.stringify({ enrichedVars: {}, lastUpdate: new Date().toISOString() }, null, 4));
            } else {
                nodeFs.writeFileSync(filePath, JSON.stringify({ enrichedVars: enrichedVars, lastUpdate: new Date().toISOString() }, null, 4));
            }
            node.warn(`🗑️ Variable ${varToDelete} supprimée (RAM & Disque)`);
        } catch (err) {
            node.error("❌ Erreur lors de la suppression disque : " + err.message);
        }
    }

    flow.set("varSelected", null);
    msg.payload = "refresh";
    return msg;
}
return null;

// open-dialog -> Preparation d'une Boite de Dialogue Suppression
// les actions dans ui-notification doivent être configuré selon un schéma précis
const varSelected = flow.get("varSelected") || null;

if (!varSelected || varSelected === "none" || varSelected === "new") {
    msg.payload = {
        type: "warning", 
        title: "Aucune variable",
        text: "Veuillez sélectionner une variable à supprimer.",
        duration: 3000
    };
    return msg;
}

flow.set("pendingDeletion", varSelected);
// gestion dynamique du ui-notification, les mots clefs de ui-update sont spécifique au noeud
msg.payload = {
    type: "warning",
    title: "Confirmation suppression",
    text: `Voulez-vous vraiment supprimer la variable "<strong>${varSelected}</strong>" ?`,
    displayTime: 0, // Ne pas fermer automatiquement
    ui_update: {
        allowConfirm: true,
        allowDismiss: true,
        confirmText: "✅ Supprimer",
        dismissText: "❌ Annuler"
    }
};

return msg;

/*******************************************************************************
 * NOM DU NŒUD : chargeEnrichedVarsToMemory
 * RÔLE : Charger le dictionnaire maître en RAM au lancement de l'UI
 * DERNIÈRE MODIF : 24/03/2026 - Cohérence SF_Init_1 / nodeFs
 ******************************************************************************/

// --- CONFIGURATION ---
const nodeFs = global.get('nodeFs');
const filePath = global.get("rzPath");

// --- FONCTIONS DE COHÉRENCE (Identiques à SF_Init_1) ---
function defaultForType(type) {
    switch (type) {
        case "boolean": return false;
        case "int": case "number": return 0;
        case "array": return [];
        case "object": return {};
        default: return "";
    }
}

// 1. TENTATIVE DE RÉCUPÉRATION RAM
let enrichedVars = global.get("enrichedVars");

// 2. SI RAM VIDE : LECTURE PHYSIQUE DU FICHIER (nodeFs)
if (!enrichedVars || Object.keys(enrichedVars).length === 0) {
    try {
        if (nodeFs.existsSync(filePath)) {
            const rawData = nodeFs.readFileSync(filePath, 'utf8');
            const parsed = JSON.parse(rawData);
            enrichedVars = parsed.enrichedVars || {};

            // On peuple la RAM pour que le reste de l'UI fonctionne immédiatement
            global.set("enrichedVars", enrichedVars);
            node.status({ fill: "blue", shape: "dot", text: "Chargé depuis Disque" });
        } else {
            node.error("🚨 CRITIQUE : globalSave.json introuvable !");
            node.status({ fill: "red", shape: "ring", text: "Fichier absent" });
            return null;
        }
    } catch (e) {
        node.error("🚨 Erreur de lecture : " + e.message);
        return null;
    }
} else {
    node.status({ fill: "green", shape: "dot", text: "Données RAM prêtes" });
}

// 3. TRANSFERT VERS LE FLOW UI
msg.payload = enrichedVars;
return msg;

info:
// Les variables sont stockées dans deux types de stockage : "default" et "file".
// Ce nœud synchronise les variables globales avec enrichedVars.
// Il met à jour enrichedVars avec les variables globales actuelles
// et s'assure que chaque variable suit la nouvelle structure définie.

// Les variables sont structurées avec des propriétés comme nomVarG, instances, propriétés, etc.
// La fonction gère également la restauration des variables globales manquantes depuis enrichedVars.
// Elle prend en compte les instances et les sous-variables pour une synchronisation cohérente.

func:
// =================================================================
// 🔹 routerAction (SÉCURISÉ ANTI-BOUCLE)
// =================================================================

// 1. ANTI-BOUCLE : Si c'est un message de retour (refresh/save), on stoppe net.
if (msg.topic === "refresh" || msg.topic === "saveBase" || msg.topic === "saveValues") {
    return null;
}

// 2. Extraction des données (cherche à la racine OU dans payload)
let action = msg.action || (msg.payload ? msg.payload.action : null);
let prop = msg.prop || (msg.payload ? msg.payload.prop : null);

// Si aucune intention d'action n'est trouvée, on ne fait rien
if (!action || !prop) return null;

// 3. Mémoire pour le nom original (utile pour SauvResultatActions)
flow.set("propOriginalName", (prop.nomP === 'NouvelleP') ? null : prop.nomP);

// 4. Routage vers les 3 sorties
// --- SORTIE 1 : Base ---
if (action === "base") {
    msg.topic = "openEditor";
    msg.editor = "base";
    msg.prop = (prop._isNew) ? { nomP: "", nomCpletP: "", descriptionP: "", typeP: "string", optionsP: [] } : prop;
    return [msg, null, null];
}

// --- SORTIE 2 : Valeurs ---
if (action === "valeurs") {
    msg.topic = "openEditor"; // FIX BUG 2 : Réveille le v-if du template
    msg.editor = "valeurs";   // FIX BUG 2
    msg.prop = prop;
    msg.instances = flow.get("instances") || ["*"];
    return [null, msg, null];
}

// --- SORTIE 3 : Delete ---
if (action === "delete") {
    msg.topic = "delete";
    msg.prop = prop;
    return [null, null, msg];
}

return null;

// =================================================================
// 🔹 prepareTableauProprietes
// - Prépare l'objet complexe pour le Template_Proprietes
// - REQUIS : msg.payload.instances, .proprietes, .variable
// =================================================================

let varSelected = flow.get("varSelected");
let enrichedVars = global.get("enrichedVars") || {};

// Si aucune sélection, on envoie une structure vide pour éviter les erreurs Vue
if (!varSelected || !enrichedVars[varSelected]) {
    msg.payload = { proprietes: [], instances: ["*"], variable: { nomVarG: "Sélectionnez une VarG" } };
    return msg;
}

let variable = enrichedVars[varSelected];

// --- FIX : PARSING DES INSTANCES ---
let instList = variable.instances || ["*"];

// Si c'est un tableau de 1 élément qui contient des ";", on le découpe
if (Array.isArray(instList) && instList.length === 1 && instList[0].includes(';')) {
    instList = instList[0].split(';').map(s => s.trim()).filter(s => s !== "");
}
// Si jamais c'était resté une simple String
else if (typeof instList === 'string') {
    instList = instList.split(';').map(s => s.trim()).filter(s => s !== "");
}

// On s'assure que "*" est toujours là et en premier
if (!instList.includes("*")) instList.unshift("*");
// -----------------------------------

// 1. On prépare la liste des lignes (P)
let listeP = (variable.proprietes || []).map(p => {
    return {
        nomP: p.nomP,
        nomCpletP: p.nomCpletP || "",
        descriptionP: p.descriptionP || "",
        typeP: p.typeP || "string",
        optionsP: p.optionsP || [],
        valeurs: p.valeurs || {},
        defaut: (p.valeurs && p.valeurs["*"]) !== undefined ? p.valeurs["*"] : "-"
    };
});

// 2. Ajout ligne "NouvelleP"
listeP.push({ nomP: 'NouvelleP', _isNew: true, typeP: 'string' });

// 3. Stockage des instances PROPRES dans le flow
flow.set("instances", instList);

// 4. On construit le payload pour le Template HTML
msg.payload = {
    proprietes: listeP,
    instances: instList, // Ici on envoie le tableau découpé
    variable: { nomVarG: variable.nomVarG }
};

return msg;

// =================================================================
// 🔹 SauvResultatActions (CODE COMPLET)
// =================================================================

const nodeFs = global.get('nodeFs');
const filePath = global.get("rzPath");

let enriched = global.get('enrichedVars') || {};
let varSelected = flow.get('varSelected');
let originalName = flow.get("propOriginalName");

if (!varSelected || !enriched[varSelected]) return null;
let variable = enriched[varSelected];

// --- CAS A : Sauvegarde Structure (Base) ---
if (msg.topic === "saveBase") {
    let p = msg.payload;

    // 1. Mise à jour des instances si présentes (Parsing par virgule ou ;)
    if (msg.instancesInput) {
        let newInst = msg.instancesInput.split(/[ ,;]+/).map(s => s.trim()).filter(s => s !== "");
        if (!newInst.includes("*")) newInst.unshift("*");
        variable.instances = newInst;
    }

    let idx = variable.proprietes.findIndex(pr => pr.nomP === originalName);

    // On conserve les valeurs existantes même si on change la structure
    let oldProp = (idx >= 0) ? variable.proprietes[idx] : { valeurs: {} };

    let updatedProp = {
        nomP: p.nomP,
        nomCpletP: p.nomCpletP || "",
        descriptionP: p.descriptionP || "",
        typeP: p.typeP || "string",
        optionsP: Array.isArray(p.optionsP) ? JSON.parse(JSON.stringify(p.optionsP)) : [],
        valeurs: oldProp.valeurs || { "*": "" }
    };

    // Initialisation des clés manquantes pour les nouvelles instances
    (variable.instances || ["*"]).forEach(i => {
        if (updatedProp.valeurs[i] === undefined) updatedProp.valeurs[i] = "";
    });

    if (idx === -1) {
        variable.proprietes.push(updatedProp);
    } else {
        variable.proprietes[idx] = updatedProp;
    }
}

// --- CAS B : Sauvegarde Valeurs ---
else if (msg.topic === "saveValues") {
    if (msg.prop && msg.prop.nomP) {
        let idx = variable.proprietes.findIndex(pr => pr.nomP === msg.prop.nomP);
        if (idx >= 0) {
            // On écrase le dictionnaire de valeurs avec celui venant de l'éditeur
            variable.proprietes[idx].valeurs = JSON.parse(JSON.stringify(msg.prop.valeurs));
        }
    }
}

// --- CAS C : Suppression ---
else if (msg.topic === "delete") {
    if (msg.prop && msg.prop.nomP) {
        variable.proprietes = variable.proprietes.filter(p => p.nomP !== msg.prop.nomP);
    }
}

// --- PERSISTANCE ---
global.set('enrichedVars', enriched);
try {
    nodeFs.writeFileSync(filePath, JSON.stringify({
        enrichedVars: enriched,
        lastUpdate: new Date().toISOString()
    }, null, 4), 'utf8');
} catch (err) {
    node.error("Erreur écriture JSON: " + err);
}

// --- SORTIE REFRESH ---
return {
    topic: "refresh",
    payload: true
};

// Noeud "Gestion Sélection Automatique" - VERSION CORRIGÉE
let varSelected = msg.payload;

console.log("Gestion Sélection Automatique - varSelected:", varSelected);

if (varSelected && varSelected !== "new") {
    // Variable existante sélectionnée
    flow.set('varSelected', varSelected);
    console.log("Variable sélectionnée automatiquement:", varSelected);

    // Préparer les messages pour les deux composants
    let formMsg = {
        topic: "refresh",
        payload: varSelected,
        info: `✅ Vous êtes sur la variable : ${varSelected}`
    };

    let tableauMsg = {
        topic: 'refresh',
        view: 'tableau',
        payload: varSelected
    };

    return [formMsg, tableauMsg];

} else if (varSelected === "new") {
    // Nouvelle variable
    flow.set('varSelected', "new");

    // Préparer les messages pour les deux composants
    let formMsg = {
        topic: "newVarG",
        info: "➕ Création d'une nouvelle variable.",
        payload: {
            nomVarG: "",
            nomCpletVarG: "",
            instances: "*",
            descriptionVarG: "- Objectif(s): - Origine: - Autres : ",
            dateUpdateVarG: new Date().toISOString()
        }
    };

    let tableauMsg = {
        topic: 'refresh',
        view: 'tableau',
        payload: "new"
    };

    return [formMsg, tableauMsg];

} else {
    // Aucune sélection
    return [null, null];
}

// Noeud "Initialisation Page"
// S'exécute au chargement de la page pour reset l'état

// Reset les sélections au chargement
flow.set('varSelected', null);
flow.set('propSelected', null);
flow.set('infoAction', "Sélectionnez une variable");

// Préparer un tableau vide
msg.payload = {
    proprietes: [{
        nomP: 'NouvelleP',
        nomCpletP: 'New',
        typeP: null,
        schema: null,
        valeurs: { '*': null },
        _isNew: true
    }],
    propSelected: null,
    instances: [],
    variable: { nomVarG: "Aucune variable sélectionnée" }
};
msg.info = "Sélectionnez une variable dans le tableau";

return msg;

// Voir ce qui existe dans le stockage fichier
let fileData = global.get("enrichedVars", "file");
node.warn("Données dans le fichier: " + JSON.stringify(fileData));

// Voir tous les keys disponibles (si supporté)
try {
    let keys = global.keys("file");
    node.warn("Clés disponibles dans le fichier: " + JSON.stringify(keys));
} catch(e) {
    node.warn("keys() non supporté: " + e.message);
}

// Chargement exemple de variables complexes

let variables = {
    EXPR: {
        type: "complex",
        properties: {
            "Bonjour": {
                actions: [
                    {
                        device: "app-SE",
                        type: "TTS",
                        value: "Bonjour"
                    }
                ]
            },
            "Oui": {
                actions: [
                    {
                        device: "app-SE",
                        type: "TTS",
                        value: "Oui"
                    },
                    {
                        device: "app-A",
                        type: "LRUB",
                        target: "ar_gd0",
                        color: "orange",
                        mode: "blink"
                    }
                ]
            }
        }
    }
};

global.set("variables", variables);

global.set("modeRZ", "VEILLE");
global.set("emergency", false);

return msg;

let vars = global.get("variables") || {};
let v = msg.payload.variable;
let p = msg.payload.property;

if (!vars[v]) {
    msg.error = "UNKNOWN_VARIABLE";
    return [null, msg];
}

if (!vars[v].properties[p]) {
    msg.error = "UNKNOWN_PROPERTY";
    return [null, msg];
}

msg.plan = {
    intent: `${v}:${p}`,
    actions: vars[v].properties[p].actions,
    meta: {
        source: msg.payload.source || "UNKNOWN",
        priority: "NORMAL"
    }
};

return [msg, null];

let modeRZ = global.get("modeRZ");
let emergency = global.get("emergency");

let accepted = [];
let refused = [];

for (let act of msg.plan.actions) {

    if (act.type === "MTR") {
        if (emergency === true) {
            refused.push({action: act, reason: "EMERGENCY"});
            continue;
        }
        if (!["VEILLE", "DEPLACEMENT"].includes(modeRZ)) {
            refused.push({action: act, reason: "MODE_INCOMPATIBLE"});
            continue;
        }
    }

    if (act.type === "SERVO") {
        if (!["FIXE", "VEILLE", "DEPLACEMENT"].includes(modeRZ)) {
            refused.push({action: act, reason: "MODE_INCOMPATIBLE"});
            continue;
        }
    }

    accepted.push(act);
}

if (accepted.length === 0) {
    msg.status = "REFUSED";
    msg.refused = refused;
    return [null, msg];
}

msg.status = "ACCEPTED";
msg.acceptedActions = accepted;
return [msg, null];

let vpivs = [];

for (let act of msg.acceptedActions) {
    vpivs.push({
        vpiv: {
            app: act.device,
            var: act.type,
            prop: act.target || "",
            value: act.value || {
                color: act.color,
                mode: act.mode
            }
        }
    });
}

msg.vpivs = vpivs;
return msg;

/*
 * parseVPIV
 * ---------
 * Chemin     : flux Diag_SE_Statut - Node-RED SP
 * Objectif   : decoder une trame VPIV de la forme
 *              $CAT:VAR:PROP:INST:VALEUR#
 * Entree     : msg.payload = trame brute (string)
 * Sortie     : msg.vpiv = { cat, varAbbr, prop, inst, value }
 *              msg.rawTrame = trame brute pour affichage
 * Articulation :
 *   -> sw_route_vpiv_v2 (switch sur varAbbr)
 *   -> dbg_trame_brute_v2 (debug)
 * Precautions :
 *   Valeurs numeriques transmises en entiers :
 *     Gyro : rad/s * 100
 *     Mag  : uT * 100, deg * 10
 *     Sys  : % direct, degres Celsius direct
 * Version : 1.0 - 2026-04-27 - Vincent Philippe
 */

const raw = (msg.payload || '').toString().trim();
msg.rawTrame = raw;

// Regex VPIV : $CAT:VAR:PROP:INST:VALEUR#
// VALEUR peut contenir {}, [], virgules, guillemets
const m = raw.match(/^\$([A-Z]):([^:]+):([^:]+):([^:]+):([\s\S]+?)#$/);

if (!m) {
    node.warn('parseVPIV : trame non reconnue : ' + raw);
    msg.vpiv = null;
    return msg;  // transmet quand meme pour le debug brut
}

const [_, cat, varAbbr, prop, inst, value] = m;
msg.vpiv = { cat, varAbbr, prop, inst, value };
msg.payload = msg.vpiv;

return msg;

/*
 * Extraire Sys
 * ------------
 * Chemin     : flux Diag_SE_Statut
 * Objectif   : extraire les metriques systeme depuis la trame VPIV
 * Entree     : msg.vpiv.prop, msg.vpiv.value
 * Sortie     : msg.sysCpu, msg.sysMem, msg.sysStorage,
 *              msg.sysBatt, msg.sysThermal, msg.sysUptime
 *              OU msg.sysRawVal si valeur non-JSON
 * Trame type : $F:Sys:dataContSys:*:{"cpu":42,"mem":58,...}#
 * Unites (doc ref SE) :
 *   cpu, mem, storage, batt : % (0-100)
 *   thermal : degres Celsius
 *   batt    : SENS INVERSE -> alerte si EN DESSOUS du seuil
 * Version : 1.0 - 2026-04-27 - Vincent Philippe
 */

const v = msg.vpiv;
if (!v) return null;

// Tentative de parsing JSON de la valeur
let parsed = null;
try {
    parsed = JSON.parse(v.value);
} catch(e) {
    parsed = null;  // valeur texte simple (ex: statusSys = 'OK')
}

if (parsed && typeof parsed === 'object') {
    msg.sysCpu     = (typeof parsed.cpu     !== 'undefined') ? parsed.cpu     : '-';
    msg.sysMem     = (typeof parsed.mem     !== 'undefined') ? parsed.mem     : '-';
    msg.sysStorage = (typeof parsed.storage !== 'undefined') ? parsed.storage : '-';
    msg.sysBatt    = (typeof parsed.batt    !== 'undefined') ? parsed.batt    : '-';
    msg.sysThermal = (typeof parsed.thermal !== 'undefined') ? parsed.thermal : '-';
    msg.sysUptime  = (typeof parsed.uptime  !== 'undefined') ? parsed.uptime  : '-';
} else {
    // Valeur brute (statusSys OK, ERROR...)
    msg.sysRawVal = v.value;
    msg.sysCpu = msg.sysMem = msg.sysStorage = '-';
    msg.sysBatt = msg.sysThermal = msg.sysUptime = '-';
}

return msg;

/*
 * Extraire Gyro
 * -------------
 * Chemin     : flux Diag_SE_Statut
 * Objectif   : extraire les axes Gx Gy Gz depuis la trame VPIV
 * Entree     : msg.vpiv.prop, msg.vpiv.value
 * Sortie     : msg.gyroGx/Gy/Gz (bruts, entiers)
 *              msg.gyroGxReal/GyReal/GzReal (divises par 100 -> rad/s)
 *              msg.gyroTs (timestamp ms)
 * Trame type : $F:Gyro:dataContGyro:*:[120,-45,300]#
 * Unites :
 *   Valeurs brutes = rad/s * 100 (entiers, table A SE v3)
 *   Affichage     = divise par 100 => rad/s reel
 * Note importante (synthese_arduino_nodered.md) :
 *   SP doit relayer Gz vers Arduino :
 *   $V:Odom:*:gyro:<gz_dps>,<ts_ms>#
 *   Ce relai n'est PAS dans ce flux de diagnostic.
 * Version : 1.0 - 2026-04-27 - Vincent Philippe
 */

const v = msg.vpiv;
if (!v) return null;

// Parsing du tableau JSON [gx, gy, gz]
let axes = null;
try {
    axes = JSON.parse(v.value);
} catch(e) {
    node.warn('Gyro : impossible de parser : ' + v.value);
    return null;
}

if (!Array.isArray(axes) || axes.length < 3) {
    node.warn('Gyro : tableau [gx,gy,gz] attendu, recu : ' + v.value);
    return null;
}

// Valeurs brutes (entiers, rad/s x100)
msg.gyroGx = axes[0];
msg.gyroGy = axes[1];
msg.gyroGz = axes[2];

// Valeurs reelles (rad/s)
msg.gyroGxReal = (axes[0] / 100).toFixed(2);
msg.gyroGyReal = (axes[1] / 100).toFixed(2);
msg.gyroGzReal = (axes[2] / 100).toFixed(2);

// Timestamp pour relai futur vers Arduino (Odom)
msg.gyroTs = Date.now();

return msg;

/*
 * Dispatch Sys -> UI
 * ------------------
 * ui-text affiche msg.payload (pas msg.sysCpu etc.)
 * On envoie 6 messages separes, un par metrique.
 * Chaque sortie alimente un ui-text distinct.
 * Ordre sorties : cpu, mem, storage, batt, thermal, uptime
 */
const cpu     = (msg.sysCpu     !== undefined) ? String(msg.sysCpu)     : '-';
const mem     = (msg.sysMem     !== undefined) ? String(msg.sysMem)     : '-';
const storage = (msg.sysStorage !== undefined) ? String(msg.sysStorage) : '-';
const batt    = (msg.sysBatt    !== undefined) ? String(msg.sysBatt)    : '-';
const thermal = (msg.sysThermal !== undefined) ? String(msg.sysThermal) : '-';
const uptime  = (msg.sysUptime  !== undefined) ? String(msg.sysUptime)  : '-';

return [
    { payload: cpu     },
    { payload: mem     },
    { payload: storage },
    { payload: batt    },
    { payload: thermal }
];

/*
 * Dispatch Gyro -> UI
 * -------------------
 * Envoie 3 messages separes (Gx, Gy, Gz) vers les ui-text.
 * Ordre sorties : Gx, Gy, Gz
 */
const gx = (msg.gyroGxReal !== undefined) ? String(msg.gyroGxReal) : '-';
const gy = (msg.gyroGyReal !== undefined) ? String(msg.gyroGyReal) : '-';
const gz = (msg.gyroGzReal !== undefined) ? String(msg.gyroGzReal) : '-';

return [
    { payload: gx },
    { payload: gy },
    { payload: gz }
];
